      tier: { bsonType: "string", enum: ["strategic", "midmarket", "standard"] },
      status: { bsonType: "string", enum: ["active", "at-risk", "churned"] },
      createdAt: { bsonType: "date" },
    },
  },
};

export async function ensureSchema(db) {
  try {
    await db.createCollection(COLLECTION, {
      validator: VALIDATOR,
      validationAction: "error",
      validationLevel: "strict",
    });
  } catch (error) {
    if (error?.code !== 48 && error?.codeName !== "NamespaceExists") throw error;
    await db.command({
      collMod: COLLECTION,
      validator: VALIDATOR,
      validationAction: "error",
      validationLevel: "strict",
    });
  }

  await db.collection(COLLECTION).createIndex({ accountId: 1 }, { unique: true, name: "accountId_1" });
}

